# 1. 페이지 설정
st.set_page_config(layout="wide", page_title="교사 시간표 관리자")

# 2. 데이터 파싱 함수 (따옴표 내 줄바꿈 대응)
def parse_fixed_data(text):
    columns = ['교사명', 
               '월1', '월2', '월3', '월4', '월5', '월6', 
               '화1', '화2', '화3', '화4', '화5', '화6', '화7',
               '수1', '수2', '수3', '수4', '수5', '수6',
               '목1', '목2', '목3', '목4', '목5', '목6',
               '금1', '금2', '금3', '금4', '금5', '금6', '금7']
    
    f = io.StringIO(text.strip())
    # 탭으로 구분하되 따옴표 내부의 줄바꿈을 허용함
    reader = csv.reader(f, delimiter='\t', quotechar='"')
    
    rows = []
    for row in reader:
        if not row or "교사명" in row[0]: continue  # 헤더 스킵
        # 33칸 맞춤 (부족하면 채우고 넘치면 자름)
        if len(row) < 33:
            row += [""] * (33 - len(row))
        else:
            row = row[:33]
        rows.append(row)
    
    return pd.DataFrame(rows, columns=columns)

