# 4. 메인 화면 구성
st.title("🏫 시간표 정상화 시뮬레이터 (90인 통합판)")

# 임시 대기석 표시
st.subheader("📥 임시 대기석 (들고 있는 수업 칩)")
if st.session_state.buffer:
    buf_len = len(st.session_state.buffer)
    cols = st.columns(min(buf_len, 6)) # 한 줄에 최대 6개 표시
    for i, chip in enumerate(st.session_state.buffer):
        with cols[i % 6]:
            st.warning(f"**{chip['teacher']}**\n{chip['lesson']}")
            if st.button(f"되돌리기 #{i+1}", key=f"rev_{i}"):
                df.loc[df['교사명'] == chip['teacher'], chip['orig_slot']] = chip['lesson']
                st.session_state.buffer.pop(i)
                st.rerun()
else:
    st.info("이동할 수업을 아래에서 '📤 빼기' 하세요.")

st.divider()

# 메인 조작 및 표 보기
c1, c2 = st.columns([1, 4])
with c1:
    st.write("### 🛠️ 수업 이동")
    search = st.text_input("이름으로 검색", placeholder="예: 기나현")
    t_list = df[df['교사명'].str.contains(search)]["교사명"].tolist() if search else df["교사명"].tolist()
    
    sel_t = st.selectbox("교사 선택", t_list)
    sel_s = st.selectbox("시간(교시) 선택", df.columns[1:])
    
    st.write("---")
    # 버튼 배치
    if st.button("📤 대기석으로 빼기", use_container_width=True):
        lesson = df.loc[df['교사명'] == sel_t, sel_s].values[0]
        if lesson:
            st.session_state.buffer.append({"teacher": sel_t, "lesson": lesson, "orig_slot": sel_s})
            df.loc[df['교사명'] == sel_t, sel_s] = ""
            st.rerun()
        else:
            st.error("빈 칸입니다!")

    if st.session_state.buffer:
        if st.button("📥 여기에 넣기", use_container_width=True):
            # 가장 마지막에 뺀 칩을 우선 배치
            chip = st.session_state.buffer[-1]
            # 중복 체크 로직
            target_class = chip['lesson'].split('\n')[0].strip()
            teacher_busy = df.loc[df['교사명'] == sel_t, sel_s].values[0] != ""
            class_busy = any(df[sel_s].str.contains(target_class, na=False))
            
            if teacher_busy:
                st.error("교사 중복: 해당 교사는 이미 수업이 있습니다.")
            elif class_busy:
                st.error(f"학급 중복: {target_class}반은 이미 수업 중입니다.")
            else:
                df.loc[df['교사명'] == sel_t, sel_s] = chip['lesson']
                st.session_state.buffer.pop()
                st.success("배치 완료!")
                st.rerun()

with c2:
    st.write("### 📅 전체 시간표 현황")
    # 90명을 한눈에 보기 편하도록 높이 조절 및 텍스트 래핑
    st.dataframe(df, height=800, use_container_width=True)

# 사이드바 데이터 관리
with st.sidebar:
    st.header("💾 데이터 관리")
    if st.button("최종 시간표 엑셀 저장"):
        df.to_excel("final_timetable.xlsx", index=False)
        st.success("파일이 저장되었습니다!")
